import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Fetch error:", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  return (
    <div className="bg-white font-sans min-h-screen">
      {/* Header Section */}
      <section className="pt-32 pb-16 px-6 max-w-7xl mx-auto">
        <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
      </section>

      {/* JOBS TABLE */}
      <section className="px-6 max-w-7xl mx-auto pb-24">

        {/* --- TABLE HEADERS --- */}
        <div className="hidden md:grid grid-cols-12 px-4 pb-4 border-b border-gray-200">
          <div className="md:col-span-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">
            Job Title
          </div>
          <div className="md:col-span-2 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">
            Location
          </div>
          <div className="md:col-span-2 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400 pl-4">
            Salary
          </div>
          <div className="md:col-span-3 text-right text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">
            Action
          </div>
        </div>

        {/* --- JOBS LISTING --- */}
        <div className="divide-y divide-gray-100">
          {loading ? (
            <div className="py-20 text-center text-gray-300 font-bold tracking-widest animate-pulse">
              LOADING POSITIONS...
            </div>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="grid grid-cols-1 md:grid-cols-12 items-center py-10 hover:bg-gray-50 transition-colors px-4">

                {/* 1. Title Column */}
                <div className="md:col-span-5">
                  <h3 className="text-2xl text-gray-700 font-normal tracking-tight">
                    {job.title}
                  </h3>
                </div>

                {/* 2. Location Column */}
                <div className="md:col-span-2 mt-2 md:mt-0">
                  <p className="text-gray-500 font-medium text-sm flex items-center gap-2">
                    <span className="text-gray-300">📍</span> {job.loc}
                  </p>
                </div>

                {/* 3. Salary Column */}
                <div className="md:col-span-2 mt-1 md:mt-0 pl-0 md:pl-4">
                  <p className="text-gray-400 font-medium text-sm">
                    {job.salary}
                  </p>
                </div>

                {/* 4. Button Column */}
                <div className="md:col-span-3 mt-6 md:mt-0 text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-10 py-3.5 rounded-full font-bold text-xs uppercase tracking-widest hover:bg-orange-600 transition-all shadow-sm"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-20 text-center text-gray-400">
              No current openings.
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Careers;
